161	// updateDefaultCAPackageVolume adds the default CA package ConfigMap volume
162	// and mount to the deployment when the feature is enabled. It also sets the
163	// hash annotation on the pod template to trigger rolling restarts when the
164	// CA bundle content changes.
165	func updateDefaultCAPackageVolume(deployment *appsv1.Deployment, config v1alpha1.DefaultCAPackageConfig, caBundleHash string) {
166		if !defaultCAPackageEnabled(config) {
167			return
168		}
169	
170		if deployment.Spec.Template.Annotations == nil {
171			deployment.Spec.Template.Annotations = make(map[string]string)
172		}
173		deployment.Spec.Template.Annotations[defaultCAPackageHashAnnotation] = caBundleHash
174	
175		// Remove any existing volume with the same name to avoid duplicates.
176		var volumes []corev1.Volume
177		for _, vol := range deployment.Spec.Template.Spec.Volumes {
178			if vol.Name != defaultCAPackageVolumeName {
179				volumes = append(volumes, vol)
180			}
181		}
182		deployment.Spec.Template.Spec.Volumes = append(volumes, corev1.Volume{
183			Name: defaultCAPackageVolumeName,
184			VolumeSource: corev1.VolumeSource{
185				ConfigMap: &corev1.ConfigMapVolumeSource{
186					LocalObjectReference: corev1.LocalObjectReference{
187						Name: defaultCAPackageConfigMapName,
188					},
189				},
190			},
191		})
192	
193		// Remove any existing volume mount at the same path, then add ours.
194		for i, container := range deployment.Spec.Template.Spec.Containers {
195			if container.Name == trustManagerContainerName {
196				var mounts []corev1.VolumeMount
197				for _, vm := range container.VolumeMounts {
198					if vm.MountPath != defaultCAPackageMountPath {
199						mounts = append(mounts, vm)
200					}
201				}
202				deployment.Spec.Template.Spec.Containers[i].VolumeMounts = append(mounts, corev1.VolumeMount{
203					Name:      defaultCAPackageVolumeName,
204					MountPath: defaultCAPackageMountPath,
205					ReadOnly:  true,
206				})
207				break
208			}
209		}
210	}
