212	func updateImage(deployment *appsv1.Deployment) error {
213		image := os.Getenv(trustManagerImageNameEnvVarName)
214		if image == "" {
215			return fmt.Errorf("%s environment variable with trust-manager image not set", trustManagerImageNameEnvVarName)
216		}
217		for i, container := range deployment.Spec.Template.Spec.Containers {
218			if container.Name == trustManagerContainerName {
219				deployment.Spec.Template.Spec.Containers[i].Image = image
220			}
221		}
222		return nil
223	}
