225	func updateResourceRequirements(deployment *appsv1.Deployment, trustManager *v1alpha1.TrustManager) error {
226		resources := trustManager.Spec.TrustManagerConfig.Resources
227		if len(resources.Limits) == 0 && len(resources.Requests) == 0 {
228			return nil
229		}
230		if err := common.ValidateResourceRequirements(resources, trustManagerConfigFieldPath); err != nil {
231			return err
232		}
233		for i := range deployment.Spec.Template.Spec.Containers {
234			if deployment.Spec.Template.Spec.Containers[i].Name == trustManagerContainerName {
235				deployment.Spec.Template.Spec.Containers[i].Resources = resources
236			}
237		}
238		return nil
239	}
