278	func (r *Reconciler) updateVolumes(deployment *appsv1.Deployment, istiocsr *v1alpha1.IstioCSR, resourceLabels map[string]string) error {
279		// Use user-configured CA certificate if provided
280		if istiocsr.Spec.IstioCSRConfig.CertManager.IstioCACertificate != nil {
281			if err := r.handleUserProvidedCA(deployment, istiocsr, resourceLabels); err != nil {
282				return common.FromError(err, "failed to validate and mount CA certificate ConfigMap")
283			}
284			return nil
285		}
286	
287		// Fall back to issuer-based CA certificate if CA certificate is not configured
288		// Handle issuer-based CA configuration
289		if err := r.handleIssuerBasedCA(deployment, istiocsr, resourceLabels); err != nil {
290			return err
291		}
292	
293		return nil
294	}
