415	func updateVolumeWithIssuerCA(deployment *appsv1.Deployment) {
416		const (
417			caVolumeName = "root-ca"
418		)
419		var (
420			defaultMode = int32(420)
421		)
422	
423		desiredVolumeMount := corev1.VolumeMount{
424			Name:      caVolumeName,
425			MountPath: caVolumeMountPath,
426			ReadOnly:  true,
427		}
428	
429		desiredVolume := corev1.Volume{
430			Name: caVolumeName,
431			VolumeSource: corev1.VolumeSource{
432				ConfigMap: &corev1.ConfigMapVolumeSource{
433					LocalObjectReference: corev1.LocalObjectReference{
434						Name: IstiocsrCAConfigMapName,
435					},
436					Items: []corev1.KeyToPath{
437						{
438							Key:  IstiocsrCAKeyName,
439							Path: IstiocsrCAKeyName,
440							Mode: &defaultMode,
441						},
442					},
443					DefaultMode: &defaultMode,
444				},
445			},
446		}
447	
448		// Update or append volume mount in the istio-csr container
449		for i, container := range deployment.Spec.Template.Spec.Containers {
450			if container.Name == istiocsrContainerName {
451				volumeMountExists := false
452				for j, vm := range container.VolumeMounts {
453					if vm.Name == caVolumeName {
454						deployment.Spec.Template.Spec.Containers[i].VolumeMounts[j] = desiredVolumeMount
455						volumeMountExists = true
456						break
457					}
458				}
459				if !volumeMountExists {
460					deployment.Spec.Template.Spec.Containers[i].VolumeMounts = append(
461						deployment.Spec.Template.Spec.Containers[i].VolumeMounts,
462						desiredVolumeMount,
463					)
464				}
465				break
466			}
467		}
468	
469		// Update or append volume in the deployment
470		volumeExists := false
471		for i, vol := range deployment.Spec.Template.Spec.Volumes {
472			if vol.Name == caVolumeName {
473				deployment.Spec.Template.Spec.Volumes[i] = desiredVolume
474				volumeExists = true
475				break
476			}
477		}
478		if !volumeExists {
479			deployment.Spec.Template.Spec.Volumes = append(
480				deployment.Spec.Template.Spec.Volumes,
481				desiredVolume,
482			)
483		}
484	}
