492	func (r *Reconciler) disallowMultipleIstioCSRInstances(istiocsr *v1alpha1.IstioCSR) error {
493		statusMessage := fmt.Sprintf("multiple instances of istiocsr exists, %s/%s will not be processed", istiocsr.GetNamespace(), istiocsr.GetName())
494	
495		if containsProcessingRejectedAnnotation(istiocsr) {
496			r.log.V(4).Info("%s/%s istiocsr resource contains processing rejected annotation", istiocsr.Namespace, istiocsr.Name)
497			// ensure status is updated.
498			var updateErr error
499			if istiocsr.Status.SetCondition(v1alpha1.Ready, metav1.ConditionFalse, v1alpha1.ReasonFailed, statusMessage) {
500				updateErr = r.updateCondition(istiocsr, nil)
501			}
502			return common.NewMultipleInstanceError(utilerrors.NewAggregate([]error{errors.New(statusMessage), updateErr}))
503		}
504	
505		istiocsrList := &v1alpha1.IstioCSRList{}
506		if err := r.List(r.ctx, istiocsrList); err != nil {
507			return fmt.Errorf("failed to fetch list of istiocsr resources: %w", err)
508		}
509	
510		if len(istiocsrList.Items) <= 1 {
511			return nil
512		}
513	
514		ignoreProcessing := false
515		for _, item := range istiocsrList.Items {
516			if item.GetNamespace() == istiocsr.Namespace {
517				continue
518			}
519			if item.CreationTimestamp.Time.Before(istiocsr.CreationTimestamp.Time) ||
520				// Even when timestamps are equal will skip processing. And if this ends
521				// up in ignoring all istiocsr instances, which means user must have created
522				// all in parallel, onus is on user to delete all and recreate just one required
523				// instance of istiocsr.
524				item.CreationTimestamp.Time.Equal(istiocsr.CreationTimestamp.Time) {
525				ignoreProcessing = true
526			}
527		}
528	
529		if !ignoreProcessing {
530			// This is the oldest instance, allow it to proceed
531			return nil
532		}
533	
534		// This instance should be rejected as there's an older or equally old instance
535		var condUpdateErr, annUpdateErr error
536		if istiocsr.Status.SetCondition(v1alpha1.Ready, metav1.ConditionFalse, v1alpha1.ReasonFailed, statusMessage) {
537			condUpdateErr = r.updateCondition(istiocsr, nil)
538		}
539		if addProcessingRejectedAnnotation(istiocsr) {
540			if err := r.UpdateWithRetry(r.ctx, istiocsr); err != nil {
541				annUpdateErr = fmt.Errorf("failed to update reject processing annotation to %s/%s: %w", istiocsr.GetNamespace(), istiocsr.GetName(), err)
542			}
543		}
544		if condUpdateErr != nil || annUpdateErr != nil {
545			return utilerrors.NewAggregate([]error{condUpdateErr, annUpdateErr})
546		}
547	
548		return common.NewMultipleInstanceError(errors.New(statusMessage))
549	}
