func TestValidateDeploymentManifest(t *testing.T) {
	tests := []struct {
		name      string
		modify    func(*appsv1.Deployment)
		wantErr   string
		overrideRequiredVolumes []string
	}{
		{
			name:   "valid manifest passes validation",
			modify: func(d *appsv1.Deployment) {},
		},
		{
			name: "missing container returns error",
			modify: func(d *appsv1.Deployment) {
				d.Spec.Template.Spec.Containers = []corev1.Container{
					{Name: "wrong-name"},
				}
			},
			wantErr: fmt.Sprintf("deployment manifest missing required container %q", istiocsrContainerName),
		},
		{
			name: "empty containers returns error",
			modify: func(d *appsv1.Deployment) {
				d.Spec.Template.Spec.Containers = nil
			},
			wantErr: fmt.Sprintf("deployment manifest missing required container %q", istiocsrContainerName),
		},
		{
			name: "missing required volume returns error",
			modify: func(d *appsv1.Deployment) {
				d.Spec.Template.Spec.Volumes = nil
			},
			overrideRequiredVolumes: []string{"must-have-volume"},
			wantErr:                `deployment manifest missing required volume "must-have-volume"`,
		},
		{
			name: "required volume present passes",
			modify: func(d *appsv1.Deployment) {
				d.Spec.Template.Spec.Volumes = []corev1.Volume{
					{Name: "must-have-volume"},
				}
			},
			overrideRequiredVolumes: []string{"must-have-volume"},
		},
		{
			name: "one of multiple required volumes missing",
			modify: func(d *appsv1.Deployment) {
				d.Spec.Template.Spec.Volumes = []corev1.Volume{
					{Name: "vol-a"},
				}
			},
			overrideRequiredVolumes: []string{"vol-a", "vol-b"},
			wantErr:                `deployment manifest missing required volume "vol-b"`,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			deployment := testDeployment()
			tt.modify(deployment)

			if tt.overrideRequiredVolumes != nil {
				original := requiredVolumes
				requiredVolumes = tt.overrideRequiredVolumes
				defer func() { requiredVolumes = original }()
			}

			err := validateDeploymentManifest(deployment)

			if tt.wantErr == "" {
				if err != nil {
					t.Fatalf("expected no error, got: %v", err)
				}
				return
			}

			if err == nil {
				t.Fatalf("expected error %q, got nil", tt.wantErr)
			}
			if err.Error() != tt.wantErr {
				t.Errorf("error mismatch:\ngot:  %q\nwant: %q", err.Error(), tt.wantErr)
			}
		})
	}
}
